parameters.query:
=SELECT order_id, status, final_order_total
FROM public.pending_orders
WHERE chat_id = {{ $('Normalize Cancel Input').first().json.chat_id }}
  AND status IN ('awaiting_confirmation', 'processing')
ORDER BY COALESCE(updated_at, created_at) DESC
LIMIT 1;

=DELETE FROM public.pending_orders
WHERE chat_id = {{ $('Normalize Cancel Input').first().json.chat_id }}
  AND status IN ('awaiting_confirmation', 'processing');

UPDATE public.carts SET status = 'expired'
WHERE user_id = {{ $('Normalize Cancel Input').first().json.chat_id }} AND status = 'active';

SELECT 'cancelled' AS result;

parameters.jsCode:
const chatId = $('Normalize Cancel Input').first().json.chat_id;
const msg = 'Your pending order was cancelled and the cart was cleared.\n\nYou can start a fresh order whenever you are ready.';
return [{ json: {
  confirmation_message: msg,
  chat_id: chatId,
  customer_ui_state: 'BROWSE_HOME',
  message_type: 'button',
  buttons: [
    { id: 'start_shopping', title: 'Shop Items' },
    { id: 'get_promos', title: 'Offers' },
  ],
} }];

const chatId = $('Normalize Cancel Input').first().json.chat_id;
const msg = 'There is nothing to cancel right now.\n\nYou can start a new order any time.';
return [{ json: {
  confirmation_message: msg,
  chat_id: chatId,
  customer_ui_state: 'BROWSE_HOME',
  message_type: 'button',
  buttons: [
    { id: 'start_shopping', title: 'Shop Items' },
    { id: 'view_cart', title: 'View Cart' },
  ],
} }];

parameters.query:
=WITH expired_cart AS (
  UPDATE public.carts SET status = 'expired', updated_at = NOW()
  WHERE user_id = {{ $('Normalize Cancel Input').first().json.chat_id }}
  AND status = 'active'
  RETURNING cart_id
)
DELETE FROM public.cart_items
WHERE cart_id IN (SELECT cart_id FROM expired_cart);
SELECT 'cleared' AS result;

parameters.jsCode:
const d = $json;
let ti = d.tool_input || {};
if (typeof ti === 'string') {
  try { ti = JSON.parse(ti); } catch(e) { ti = {}; }
}
const chatId = String(d.chat_id || ti.chat_id || '');
return [{ json: { chat_id: chatId } }];

